__kernel void nw_kernel1(__global const int* referrence, __global int* input_itemsets, __global int* output_itemsets,
                         __local int* input_itemsets_l, __local int* reference_l,
                         int max_cols, int penalty, int blk, int block_width, int worksize, int offset_r, int offset_c)
{
    int b_index_x = get_global_id(0) / BLOCK_SIZE;
    if (b_index_x >= blk) return;
    int b_index_y = blk - 1 - b_index_x;
    int local_i, local_j;

    // Load reference_l
    for (local_i = 0; local_i < BLOCK_SIZE; local_i++) {
        for (local_j = 0; local_j < BLOCK_SIZE; local_j++) {
            reference_l[local_i * BLOCK_SIZE + local_j] = referrence[max_cols * (b_index_y * BLOCK_SIZE + local_i + 1) + b_index_x * BLOCK_SIZE + local_j + 1];
        }
    }

    // Load input_itemsets_l
    for (local_i = 0; local_i < BLOCK_SIZE + 1; local_i++) {
        for (local_j = 0; local_j < BLOCK_SIZE + 1; local_j++) {
            input_itemsets_l[local_i * (BLOCK_SIZE + 1) + local_j] = input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + local_i) + b_index_x * BLOCK_SIZE + local_j];
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Compute
    for (local_i = 1; local_i < BLOCK_SIZE + 1; local_i++) {
        for (local_j = 1; local_j < BLOCK_SIZE + 1; local_j++) {
            input_itemsets_l[local_i * (BLOCK_SIZE + 1) + local_j] = maximum(
                input_itemsets_l[(local_i - 1) * (BLOCK_SIZE + 1) + local_j - 1] + reference_l[(local_i - 1) * BLOCK_SIZE + local_j - 1],
                input_itemsets_l[local_i * (BLOCK_SIZE + 1) + local_j - 1] - penalty,
                input_itemsets_l[(local_i - 1) * (BLOCK_SIZE + 1) + local_j] - penalty);
        }
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Store results
    for (local_i = 0; local_i < BLOCK_SIZE; local_i++) {
        for (local_j = 0; local_j < BLOCK_SIZE; local_j++) {
            input_itemsets[max_cols * (b_index_y * BLOCK_SIZE + local_i + 1) + b_index_x * BLOCK_SIZE + local_j + 1] = input_itemsets_l[(local_i + 1) * (BLOCK_SIZE + 1) + local_j + 1];
        }
    }
}

